diff --git a//tmp/proof-wt-96576/demo.mts b//tmp/proof-wt-96576/demo.mts
new file mode 100644
index 00000000000000000000…[40 ×'0' elided]..49abad1e036ccd0d9aa1ff3609c1693285756de8
--- /dev/null
+++ b//tmp/proof-wt-96576/demo.mts
@@ -0,0 +1,114 @@
+import { slackApprovalNativeRuntime } from "./extensions/slack/src/approval-handler.runtime.ts";
+
+const UNPAIRED_SURROGATE_RE =
+  /[\uD800-\uDBFF](?![\uDC00-\uDFFF])|(?<![\uD800-\uDBFF])[\uDC00-\uDFFF]/;
+
+function codeUnitsHex(value: string): string {
+  return Array.from({ length: value.length }, (_, index) =>
+    value.charCodeAt(index).toString(16).padStart(4, "0"),
+  ).join(" ");
+}
+
+function codePointsHex(value: string): string {
+  return Array.from(value, (char) => `U+${char.codePointAt(0)?.toString(16)}`).join(" ");
+}
+
+function readMrkdwnTexts(blocks: unknown): string[] {
+  if (!Array.isArray(blocks)) {
+    return [];
+  }
+  const texts: string[] = [];
+  for (const block of blocks) {
+    if (!block || typeof block !== "object") {
+      continue;
+    }
+    const text = (block as { text?: unknown }).text;
+    if (text && typeof text === "object") {
+      const maybeText = (text as { type?: unknown; text?: unknown }).text;
+      const maybeType = (text as { type?: unknown; text?: unknown }).type;
+      if (maybeType === "mrkdwn" && typeof maybeText === "string") {
+        texts.push(maybeText);
+      }
+    }
+    const elements = (block as { elements?: unknown }).elements;
+    if (Array.isArray(elements)) {
+      for (const element of elements) {
+        if (!element || typeof element !== "object") {
+          continue;
+        }
+        const maybeText = (element as { type?: unknown; text?: unknown }).text;
+        const maybeType = (element as { type?: unknown; text?: unknown }).type;
+        if (maybeType === "mrkdwn" && typeof maybeText === "string") {
+          texts.push(maybeText);
+        }
+      }
+    }
+  }
+  return texts;
+}
+
+const emoji = String.fromCodePoint(0x1f600);
+const commandText = `${"a".repeat(2598)}${emoji}tail`;
+const oldRawSlice = `${commandText.slice(0, 2599)}…`;
+
+console.log("BEFORE raw slice()");
+console.log(`input length=${commandText.length}`);
+console.log(`slice length=${oldRawSlice.length}`);
+console.log(`tail codeUnits=${codeUnitsHex(oldRawSlice.slice(-4))}`);
+console.log(`tail codePoints=${codePointsHex(oldRawSlice.slice(-4))}`);
+console.log(`lone-surrogate=${UNPAIRED_SURROGATE_RE.test(oldRawSlice)}`);
+try {
+  encodeURIComponent(oldRawSlice);
+  console.log("encodeURIComponent=ok");
+} catch (error) {
+  console.log(`encodeURIComponent=${error instanceof Error ? error.name : String(error)}`);
+}
+
+const payload = await slackApprovalNativeRuntime.presentation.buildPendingPayload({
+  cfg: {},
+  accountId: "default",
+  context: {
+    app: {},
+    config: {},
+  },
+  request: {
+    id: "req-surrogate-terminal-proof",
+    request: {
+      command: commandText,
+    },
+    createdAtMs: 0,
+    expiresAtMs: 60_000,
+  },
+  approvalKind: "exec",
+  nowMs: 0,
+  view: {
+    approvalKind: "exec",
+    approvalId: "req-surrogate-terminal-proof",
+    commandText,
+    metadata: [],
+    actions: [
+      {
+        decision: "allow-once",
+        label: "Allow Once",
+        command: "/approve req-surrogate-terminal-proof allow-once",
+        style: "success",
+      },
+    ],
+  },
+} as never);
+
+const commandMrkdwn = readMrkdwnTexts((payload as { blocks?: unknown }).blocks).find((entry) =>
+  entry.startsWith("*Command*"),
+);
+
+if (!commandMrkdwn) {
+  throw new Error("Expected command mrkdwn block");
+}
+
+console.log("AFTER slackApprovalNativeRuntime.presentation.buildPendingPayload()");
+console.log(`mrkdwn length=${commandMrkdwn.length}`);
+console.log(`tail text=${JSON.stringify(commandMrkdwn.slice(-16))}`);
+console.log(`tail codeUnits=${codeUnitsHex(commandMrkdwn.slice(-8))}`);
+console.log(`tail codePoints=${codePointsHex(commandMrkdwn.slice(-8))}`);
+console.log(`lone-surrogate=${UNPAIRED_SURROGATE_RE.test(commandMrkdwn)}`);
+console.log(`ends-with-ellipsis-fence=${/…\n```$/.test(commandMrkdwn)}`);

